const verseList=['JER.29.11','PSA.23.1','PRO.3.5-6','PHP.4.13','ISA.40.31','MAT.11.28','JHN.3.16','ROM.8.28','1CO.13.13','PSA.46.1','JOS.1.9','HEB.11.1','ROM.12.2','2CO.5.7','GAL.5.22-23','EPH.2.8-9','PHP.4.6-7','COL.3.23','1JN.4.19','PSA.119.105','PSA.91.1-2','MAT.6.33','ISA.41.10','ROM.15.13','PSA.37.4','PRO.16.3','MAT.5.16','2TI.1.7','PSA.27.1','HEB.13.8'];const CACHE_KEY='bible_verse_cache';function getVerseCache(){try{var raw=localStorage.getItem(CACHE_KEY);if(!raw)return{};return JSON.parse(raw);}catch(e){return{};}}
function getCachedVerse(verseId){var cache=getVerseCache();return cache[verseId]||null;}
function setCachedVerse(verseId,data){try{var cache=getVerseCache();cache[verseId]=data;localStorage.setItem(CACHE_KEY,JSON.stringify(cache));}catch(e){}}
const themeButton=document.getElementById('themeButton');function setTheme(isDark){document.documentElement.setAttribute('data-theme',isDark?'dark':'light');try{localStorage.setItem('theme',isDark?'dark':'light');}catch(e){}}
let savedTheme='light';try{savedTheme=localStorage.getItem('theme')||'light';}catch(e){}
setTheme(savedTheme==='dark');themeButton.addEventListener('click',()=>{const isDark=document.documentElement.getAttribute('data-theme')==='dark';setTheme(!isDark);});let toastTimeout=null;function showToast(message){const toast=document.getElementById('toast');toast.textContent=message;toast.classList.add('show');if(toastTimeout)clearTimeout(toastTimeout);toastTimeout=setTimeout(()=>toast.classList.remove('show'),2500);}
async function copyToClipboard(text){try{if(navigator.clipboard&&window.isSecureContext){await navigator.clipboard.writeText(text);showToast('Copied to clipboard \u2713');return;}}catch(e){}
try{const textArea=document.createElement('textarea');textArea.value=text;textArea.setAttribute('readonly','');textArea.style.cssText='position:fixed;top:-9999px;left:-9999px;opacity:0';document.body.appendChild(textArea);textArea.select();textArea.setSelectionRange(0,99999);const ok=document.execCommand('copy');document.body.removeChild(textArea);showToast(ok?'Copied to clipboard \u2713':'Copy failed');}catch(err){showToast('Copy failed');}}
const FALLBACK_VERSE={english:{quote:"For I know the plans I have for you, declares the Lord, plans for welfare and not for evil, to give you a future and a hope.",reference:"Jeremiah 29:11"},chinese:{quote:"\u8036\u548C\u83EF\u8AAA\uFF1A\u6211\u77E5\u9053\u6211\u5411\u4F60\u5011\u6240\u61F7\u7684\u610F\u5FF5\u662F\u8CDC\u5E73\u5B89\u7684\u610F\u5FF5\uFF0C\u4E0D\u662F\u964D\u707D\u798D\u7684\u610F\u5FF5\uFF0C\u8981\u53EB\u4F60\u5011\u672B\u5F8C\u6709\u6307\u671B\u3002",reference:"\u8036\u5229\u7C73\u66F8 29:11"}};async function fetchVerse(verseId){var cached=getCachedVerse(verseId);if(cached){return cached;}
try{const controller=new AbortController();const timeout=setTimeout(()=>controller.abort(),10000);const response=await fetch('/.netlify/functions/get-bible-verse?verseId='+encodeURIComponent(verseId),{signal:controller.signal});clearTimeout(timeout);if(!response.ok)throw new Error('HTTP '+response.status);const data=await response.json();if(data.isFallback){showToast('\u26A0 API \u9023\u7DDA\u5931\u6557\uFF0C\u986F\u793A\u9810\u8A2D\u7D93\u6587');return{english:data.english,chinese:data.chinese};}
if(data.error){if(data.english&&data.chinese){const result={english:data.english,chinese:data.chinese};setCachedVerse(verseId,result);return result;}
throw new Error(data.error);}
const result={english:{quote:cleanText(data.english.quote),reference:data.english.reference},chinese:{quote:cleanText(data.chinese.quote),reference:data.chinese.reference}};setCachedVerse(verseId,result);return result;}catch(error){console.error('Error fetching verse:',error.message);showToast('\u26A0 \u7121\u6CD5\u53D6\u5F97\u7D93\u6587\uFF0C\u986F\u793A\u9810\u8A2D\u7D93\u6587');return FALLBACK_VERSE;}}
function cleanText(text){if(!text)return'';return text.replace(/<[^>]*>/g,'').replace(/&[a-z]+;/gi,' ').replace(/\s+/g,' ').trim();}
function getVerseForDate(date){var start=new Date(date.getFullYear(),0,0);var dayOfYear=Math.floor((date-start)/(1000*60*60*24));return verseList[dayOfYear%verseList.length];}
function getVerseForToday(){return getVerseForDate(new Date());}
var viewingDate=null;function updateDate(date){var d=date||new Date();var options={weekday:'long',year:'numeric',month:'long',day:'numeric'};var dateEl=document.getElementById('currentDate');dateEl.textContent=d.toLocaleDateString('en-US',options);var existingBadge=dateEl.querySelector('.date-viewing');if(existingBadge)existingBadge.remove();if(date&&!isSameDay(date,new Date())){var badge=document.createElement('span');badge.className='date-viewing';badge.textContent='\u2190 \u56DE\u4ECA\u5929';badge.addEventListener('click',function(){viewingDate=null;updateDate();displayQuote();renderCalendar();});dateEl.appendChild(badge);}}
function isSameDay(a,b){return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()&&a.getDate()===b.getDate();}
let currentVerse=null;async function displayQuote(date){var d=date||new Date();var verseId=getVerseForDate(d);var verse=await fetchVerse(verseId);currentVerse=verse;var quoteEn=document.getElementById('quoteEn');var quoteZh=document.getElementById('quoteZh');var refEn=document.getElementById('referenceEn');var refZh=document.getElementById('referenceZh');quoteEn.textContent='\u201C'+verse.english.quote+'\u201D';refEn.textContent='\u2014 '+verse.english.reference;quoteZh.textContent='\u300C'+verse.chinese.quote+'\u300D';refZh.textContent='\u2014 '+verse.chinese.reference;quoteZh.className='quote chinese';refZh.className='reference chinese';}
document.getElementById('sectionEn').querySelector('.copy-button').addEventListener('click',function(e){e.stopPropagation();if(!currentVerse)return;copyToClipboard(currentVerse.english.quote+'\n\u2014 '+currentVerse.english.reference);});document.getElementById('sectionZh').querySelector('.copy-button').addEventListener('click',function(e){e.stopPropagation();if(!currentVerse)return;copyToClipboard(currentVerse.chinese.quote+'\n\u2014 '+currentVerse.chinese.reference);});const refreshButton=document.getElementById('refreshButton');let isRefreshing=false;refreshButton.addEventListener('click',async function(){if(isRefreshing)return;isRefreshing=true;refreshButton.classList.add('spinning');try{localStorage.removeItem(CACHE_KEY);}catch(e){}
viewingDate=null;updateDate();await displayQuote();renderCalendar();setTimeout(function(){refreshButton.classList.remove('spinning');isRefreshing=false;},600);});const fontButton=document.getElementById('fontButton');const fontSelector=document.getElementById('fontSelector');var currentFont='classic';try{currentFont=localStorage.getItem('font')||'classic';}catch(e){}
setFont(currentFont);function setFont(fontName){var container=document.querySelector('.container');var classes=['font-classic','font-modern','font-elegant','font-traditional','font-formal'];classes.forEach(function(c){container.classList.remove(c);});container.classList.add('font-'+fontName);document.querySelectorAll('.font-option').forEach(function(option){option.classList.toggle('active',option.dataset.font===fontName);});try{localStorage.setItem('font',fontName);}catch(e){}}
fontButton.addEventListener('click',function(e){e.stopPropagation();fontSelector.classList.toggle('show');shareMenu.classList.remove('show');document.getElementById('calendarPanel').classList.remove('show');});document.querySelectorAll('.font-option').forEach(function(option){option.addEventListener('click',function(){setFont(option.dataset.font);fontSelector.classList.remove('show');});});const shareButton=document.getElementById('shareButton');const shareMenu=document.getElementById('shareMenu');var shareFormats={story:{className:'format-story',width:1080,height:1920},post:{className:'format-post',width:1080,height:1080}};var currentShareFormat='story';var shareFormatEl=document.getElementById('shareFormat');shareFormatEl.addEventListener('click',function(e){var option=e.target.closest('.share-format-option');if(!option)return;currentShareFormat=option.dataset.format;shareFormatEl.querySelectorAll('.share-format-option').forEach(function(el){el.classList.toggle('active',el===option);});});shareButton.addEventListener('click',function(e){e.stopPropagation();fontSelector.classList.remove('show');shareMenu.classList.toggle('show');document.getElementById('calendarPanel').classList.remove('show');});async function shareAsImage(useNativeShare){if(!currentVerse)return;document.getElementById('captureQuoteEn').textContent='\u201C'+currentVerse.english.quote+'\u201D';document.getElementById('captureReferenceEn').textContent='\u2014 '+currentVerse.english.reference;document.getElementById('captureQuoteZh').textContent='\u300C'+currentVerse.chinese.quote+'\u300D';document.getElementById('captureReferenceZh').textContent='\u2014 '+currentVerse.chinese.reference;try{var captureElement=document.getElementById('quoteCapture');var format=shareFormats[currentShareFormat];captureElement.classList.remove('format-story','format-post');captureElement.classList.add(format.className);var bgColor=getComputedStyle(document.documentElement).getPropertyValue('--container-bg').trim();var canvas=await html2canvas(captureElement,{scale:1,width:format.width,height:Math.max(format.height,captureElement.offsetHeight),backgroundColor:bgColor,logging:false,useCORS:true,allowTaint:true});if(useNativeShare){if(navigator.share&&navigator.canShare){var blob=await new Promise(function(resolve){canvas.toBlob(resolve,'image/png');});var file=new File([blob],'daily-bible-quote.png',{type:'image/png'});var shareData={files:[file],title:'Daily Bible Quote',text:currentVerse.english.quote+'\n\u2014 '+currentVerse.english.reference};if(navigator.canShare(shareData)){await navigator.share(shareData);}else{downloadCanvas(canvas);}}else{downloadCanvas(canvas);}}else{downloadCanvas(canvas);}}catch(error){if(error.name!=='AbortError'){console.error('Error creating share image:',error);downloadCanvas(null);}}
shareMenu.classList.remove('show');}
function downloadCanvas(canvas){if(!canvas){showToast('Share not supported, try Download instead');return;}
var link=document.createElement('a');link.download='daily-bible-quote.png';link.href=canvas.toDataURL('image/png');link.click();showToast('Image downloaded \u2713');}
document.getElementById('shareNative').addEventListener('click',function(){shareAsImage(true);});document.getElementById('shareDownload').addEventListener('click',function(){shareAsImage(false);});document.addEventListener('click',function(e){if(!fontSelector.contains(e.target)&&e.target!==fontButton){fontSelector.classList.remove('show');}
if(!shareMenu.contains(e.target)&&e.target!==shareButton){shareMenu.classList.remove('show');}
var calPanel=document.getElementById('calendarPanel');var calBtn=document.getElementById('calendarButton');if(!calPanel.contains(e.target)&&e.target!==calBtn){calPanel.classList.remove('show');}});document.addEventListener('keydown',function(e){if(e.key==='Escape'){fontSelector.classList.remove('show');shareMenu.classList.remove('show');document.getElementById('calendarPanel').classList.remove('show');}});var calendarButton=document.getElementById('calendarButton');var calendarPanel=document.getElementById('calendarPanel');var calMonth=new Date().getMonth();var calYear=new Date().getFullYear();calendarButton.addEventListener('click',function(e){e.stopPropagation();fontSelector.classList.remove('show');shareMenu.classList.remove('show');calendarPanel.classList.toggle('show');if(calendarPanel.classList.contains('show')){var ref=viewingDate||new Date();calMonth=ref.getMonth();calYear=ref.getFullYear();renderCalendar();}});document.getElementById('calPrev').addEventListener('click',function(e){e.stopPropagation();calMonth--;if(calMonth<0){calMonth=11;calYear--;}
renderCalendar();});document.getElementById('calNext').addEventListener('click',function(e){e.stopPropagation();calMonth++;if(calMonth>11){calMonth=0;calYear++;}
renderCalendar();});document.getElementById('calTodayBtn').addEventListener('click',function(e){e.stopPropagation();viewingDate=null;calMonth=new Date().getMonth();calYear=new Date().getFullYear();updateDate();displayQuote();renderCalendar();calendarPanel.classList.remove('show');});function renderCalendar(){var today=new Date();var selected=viewingDate||today;var monthNames=['January','February','March','April','May','June','July','August','September','October','November','December'];var zhMonths=['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];document.getElementById('calTitle').textContent=monthNames[calMonth]+' '+calYear+' '+zhMonths[calMonth];var nextBtn=document.getElementById('calNext');if(calYear>today.getFullYear()||(calYear===today.getFullYear()&&calMonth>=today.getMonth())){nextBtn.style.visibility='hidden';}else{nextBtn.style.visibility='visible';}
var todayBtn=document.getElementById('calTodayBtn');if(viewingDate&&!isSameDay(viewingDate,today)){todayBtn.classList.add('show');}else{todayBtn.classList.remove('show');}
var grid=document.getElementById('calGrid');grid.innerHTML='';var firstDay=new Date(calYear,calMonth,1).getDay();var daysInMonth=new Date(calYear,calMonth+1,0).getDate();var daysInPrevMonth=new Date(calYear,calMonth,0).getDate();for(var i=firstDay-1;i>=0;i--){var dayEl=document.createElement('div');dayEl.className='calendar-day other-month';dayEl.textContent=daysInPrevMonth-i;grid.appendChild(dayEl);}
for(var d=1;d<=daysInMonth;d++){var dayEl=document.createElement('div');dayEl.className='calendar-day';dayEl.textContent=d;var thisDate=new Date(calYear,calMonth,d);if(thisDate>today){dayEl.classList.add('future');}else{(function(date){dayEl.addEventListener('click',function(e){e.stopPropagation();viewingDate=date;updateDate(date);displayQuote(date);renderCalendar();calendarPanel.classList.remove('show');});})(thisDate);}
if(isSameDay(thisDate,today)){dayEl.classList.add('today');}
if(isSameDay(thisDate,selected)){dayEl.classList.add('selected');}
grid.appendChild(dayEl);}
var totalCells=firstDay+daysInMonth;var remaining=(7-(totalCells%7))%7;for(var i=1;i<=remaining;i++){var dayEl=document.createElement('div');dayEl.className='calendar-day other-month';dayEl.textContent=i;grid.appendChild(dayEl);}}
updateDate();displayQuote();function scheduleNextUpdate(){var now=new Date();var tomorrow=new Date(now.getFullYear(),now.getMonth(),now.getDate()+1);var msUntilMidnight=tomorrow-now+1000;setTimeout(function(){updateDate();displayQuote();scheduleNextUpdate();},msUntilMidnight);}
scheduleNextUpdate();